// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

/** Aggregated result of one fuzz run: verdict histogram, skips, and every confirmed violation. */
final class FuzzRunSummary {
	private final long seed;
	private final Map<String, Integer> verdicts = new LinkedHashMap<>();
	private final List<FuzzViolation> violations = new ArrayList<>();
	private int pairs;
	private int jsonRoundTripSkips;

	FuzzRunSummary(long seed) {
		this.seed = seed;
	}

	void recordPair() {
		pairs++;
	}

	void recordVerdict(String sourceId, String status) {
		verdicts.merge(sourceId + ":" + status, 1, Integer::sum);
	}

	void recordJsonRoundTripSkip() {
		jsonRoundTripSkips++;
	}

	void record(FuzzViolation violation) {
		violations.add(violation);
	}

	List<FuzzViolation> violations() {
		return violations;
	}

	int pairCount() {
		return pairs;
	}

	String report() {
		StringBuilder result = new StringBuilder();
		result.append("Fuzz run seed=")
				.append(seed)
				.append(" pairs=")
				.append(pairs)
				.append(" violations=")
				.append(violations.size())
				.append(" jsonRoundTripSkips=")
				.append(jsonRoundTripSkips)
				.append('\n');
		verdicts.forEach((key, count) -> result.append("  ").append(key).append('=').append(count).append('\n'));
		for (FuzzViolation violation : violations) {
			result.append("  VIOLATION ").append(violation.describe()).append('\n');
		}
		return result.toString();
	}
}
